from math import prod, isqrt
from functools import lru_cache
from sympy import isprime, divisors, prime
def A368041(n):
    @lru_cache(maxsize=None)
    def mult_factors(n):
        if isprime(n):
            return [(n,)]
        c = []
        for d in divisors(n,generator=True,proper=True):
            if 1<d:
                for a in mult_factors(n//d):
                    c.append(tuple(sorted((d,)+a,reverse=True)))
        return list(set(c))
    return isqrt(min((min(prod(prime(i)**(j-1) for i,j in enumerate(d,1))<<2,prod(prime(i)**(j-1) for i,j in enumerate(d,2))) for d in mult_factors((n<<1)+1)),default=1)) # _Chai Wah Wu_, Apr 23 2026

